}

func (c *Config) validate() error {
	if c.Version != "" {
		if strings.TrimSpace(c.Version) != Version {
			return fmt.Errorf("invalid version: %s", c.Version)
		}
	}

	if c.Authorization.Required && !c.Authentication.Required {
		return errString("authorization", "requires authentication to also be required")
	}

	// Check that environment storage references exist in storage config
	for envName, env := range c.Environments {
		if env.Storage == "" {
			continue
		}

		if _, exists := c.Storage[env.Storage]; !exists {
			return errString("environments", fmt.Sprintf("%q references undefined storage %q", envName, env.Storage))
		}
	}

	// Validate templates config
	if err := c.Templates.Validate(); err != nil {
		return errFieldWrap("", "templates", err)
	}

	return nil
}

func (c *Config) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	var (
		out []byte
		err error
	)

	if r.Header.Get("Accept") == "application/json+pretty" {
		out, err = json.MarshalIndent(c, "", "  ")
	} else {
		out, err = json.Marshal(c)
	}

	if err != nil {
		w.WriteHeader(http.StatusInternalServerError)
		return
	}

	if _, err = w.Write(out); err != nil {
		w.WriteHeader(http.StatusInternalServerError)
		return
	}
}

// stringToEnumHookFunc returns a DecodeHookFunc that converts strings to a target enum
func stringToEnumHookFunc[T constraints.Integer](mappings map[string]T) mapstructure.DecodeHookFunc {
	return func(
		f reflect.Type,
		t reflect.Type,
		data any,
	) (any, error) {
		if f.Kind() != reflect.String {
			return data, nil
		}
		if t != reflect.TypeOf(T(0)) {
			return data, nil
		}

		enum := mappings[data.(string)]

		return enum, nil
	}
}

func experimentalFieldSkipHookFunc(types ...reflect.Type) mapstructure.DecodeHookFunc {
	return func(
		f reflect.Type,
		t reflect.Type,
		data any,
	) (any, error) {
		if len(types) == 0 {
			return data, nil
		}

		if t.Kind() != reflect.Struct {
			return data, nil
		}

		// skip any types that match a type in the provided set
		for _, typ := range types {
			if t == typ {
				return reflect.New(typ).Interface(), nil
			}
		}

		return data, nil
	}
}

// stringToReferenceHookFunc returns a DecodeHookFunc that handles:
// - ${env:VAR} - environment variables
// - ${secret:key} - secret references (marked as unresolved placeholders)
func stringToReferenceHookFunc() mapstructure.DecodeHookFunc {
	return func(
		f reflect.Type,
		t reflect.Type,
		data any,
	) (any, error) {
		if f.Kind() != reflect.String || f != reflect.TypeFor[string]() {
			return data, nil
		}

		str := data.(string)

		// Handle explicit environment references: ${env:VAR}
		if envReference.MatchString(str) {
			key := envReference.ReplaceAllString(str, `$1`)
			return os.Getenv(key), nil
		}

		// Secret references are left as-is and will be resolved post-load
		return data, nil
	}
}

// stringToSliceHookFunc returns a DecodeHookFunc that converts
// string to []string by splitting using strings.Fields().
func stringToSliceHookFunc() mapstructure.DecodeHookFunc {
	return func(
		f reflect.Kind,
		t reflect.Kind,
		data any,
	) (any, error) {
		if f != reflect.String || t != reflect.Slice {
			return data, nil
		}

		raw := data.(string)
		if raw == "" {
			return []string{}, nil
		}

		return strings.Fields(raw), nil
	}
}

